diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..6637aea67baf 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1317,6 +1317,7 @@ static Value *foldAndOrOfICmpsWithConstEq(ICmpInst *Cmp0, ICmpInst *Cmp1,
 /// or   (icmp Pred1 V1, C1) | (icmp Pred2 V2, C2)
 /// into a single comparison using range-based reasoning.
 /// NOTE: This is also used for logical and/or, must be poison-safe!
+
 Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
                                                      ICmpInst *ICmp2,
                                                      bool IsAnd) {
@@ -1327,6 +1328,41 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       !match(ICmp2, m_ICmp(Pred2, m_Value(V2), m_APInt(C2))))
     return nullptr;

+  auto getRangeFromMaskedICmp = [](CmpPredicate Pred, Value *V, const APInt &C,
+                                   ConstantRange &CR, Value *&Base) -> bool {
+    if (!ICmpInst::isEquality(Pred))
+      return false;
+
+    Value *X;
+    const APInt *Mask;
+    if (!match(V, m_And(m_Value(X), m_APInt(Mask))))
+      return false;
+
+    APInt LowBits = ~(*Mask);
+    if (!LowBits.isMask())
+      return false;
+
+    if ((C & LowBits) != 0)
+      return false;
+
+    APInt Width = LowBits + 1;
+    APInt Upper = C + Width;
+    CR = ConstantRange(C, Upper);
+    if (Pred == ICmpInst::ICMP_NE)
+      CR = CR.inverse();
+    Base = X;
+    return true;
+  };
+
+  ConstantRange CR1(V1->getType()->getScalarSizeInBits(), /*isFullSet=*/true);
+  ConstantRange CR2(V2->getType()->getScalarSizeInBits(), /*isFullSet=*/true);
+  bool HasCR1 = false, HasCR2 = false;
+
+  if (ICmpInst::isEquality(Pred1))
+    HasCR1 = getRangeFromMaskedICmp(Pred1, V1, *C1, CR1, V1);
+  if (ICmpInst::isEquality(Pred2))
+    HasCR2 = getRangeFromMaskedICmp(Pred2, V2, *C2, CR2, V2);
+
   // Look through add of a constant offset on V1, V2, or both operands. This
   // allows us to interpret the V + C' < C'' range idiom into a proper range.
   const APInt *Offset1 = nullptr, *Offset2 = nullptr;
@@ -1341,15 +1377,23 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   if (V1 != V2)
     return nullptr;

-  ConstantRange CR1 = ConstantRange::makeExactICmpRegion(
-      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
-  if (Offset1)
+  if (!HasCR1) {
+    CR1 = ConstantRange::makeExactICmpRegion(
+        IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
+    if (Offset1)
+      CR1 = CR1.subtract(*Offset1);
+  } else if (Offset1) {
     CR1 = CR1.subtract(*Offset1);
+  }

-  ConstantRange CR2 = ConstantRange::makeExactICmpRegion(
-      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
-  if (Offset2)
+  if (!HasCR2) {
+    CR2 = ConstantRange::makeExactICmpRegion(
+        IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
+    if (Offset2)
+      CR2 = CR2.subtract(*Offset2);
+  } else if (Offset2) {
     CR2 = CR2.subtract(*Offset2);
+  }

   Type *Ty = V1->getType();
   Value *NewV = V1;
@@ -1384,6 +1428,7 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   return Builder.CreateICmp(NewPred, NewV, ConstantInt::get(Ty, NewC));
 }

+
